/**
 * The SPARQL algebra defines {@code eval(Join(P1,P2)) = Join(eval(P1), eval(P2))}: the right operand denotes ONE
 * independently evaluated multiset. A nested-loop bind join re-evaluating a volatile right operand per left row would
 * observably deviate — each STRUUID() call must return a different value, so distinct values per row cannot arise from
 * any single evaluation of the operand. This algebra-level witness covers inner joins whose unsafe right operand is not
 * a scope change (not reachable from the parser, but reachable through programmatically constructed algebra, which is
 * public API).
 */
public class JoinIndependentOperandTest {

	@Test
	public void volatileInnerJoinRightOperandIsEvaluatedOnce() {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();

		BindingSetAssignment values = new BindingSetAssignment();
		QueryBindingSet first = new QueryBindingSet();
		first.addBinding("x", vf.createLiteral(1));
		QueryBindingSet second = new QueryBindingSet();
		second.addBinding("x", vf.createLiteral(2));
		values.setBindingSets(List.of(first, second));

		Extension volatileRight = new Extension(new SingletonSet(),
				new ExtensionElem(new FunctionCall("STRUUID"), "u"));
		QueryRoot query = new QueryRoot(new Join(values, volatileRight));

		StrictEvaluationStrategy strategy = new StrictEvaluationStrategy(new EmptyTripleSource(), null);

		List<BindingSet> rows = new ArrayList<>();
		try (CloseableIteration<BindingSet> iteration = strategy.precompile(query)
				.evaluate(EmptyBindingSet.getInstance())) {
			while (iteration.hasNext()) {
				rows.add(iteration.next());
			}
		}

		assertEquals(2, rows.size());
		Set<Value> distinctU = new HashSet<>();
		for (BindingSet row : rows) {
			distinctU.add(row.getValue("u"));
		}
		assertEquals(1, distinctU.size(),
				"the join's right operand is evaluated independently once; its single fresh value joins with every left row");
	}

	/**
	 * Zero-length paths are mapping-parameterized by contract (GH-3053): a path endpoint bound by another part of the
	 * query matches itself even when the term does not occur in the graph. Independent evaluation plus a
	 * compatible-mapping join is therefore NOT observationally equivalent for these operators — the correlated
	 * per-left-row evaluation is their defined semantics and must never be rerouted through materialized replay.
	 */
	@Test
	public void zeroLengthPathInnerJoinRightOperandStaysCorrelated() {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		IRI notInGraph = vf.createIRI("urn:not-in-graph");

		BindingSetAssignment values = new BindingSetAssignment();
		QueryBindingSet bs = new QueryBindingSet();
		bs.addBinding("x", notInGraph);
		values.setBindingSets(List.of(bs));

		QueryRoot query = new QueryRoot(new Join(values, new ZeroLengthPath(Var.of("x"), Var.of("r"))));

		StrictEvaluationStrategy strategy = new StrictEvaluationStrategy(new EmptyTripleSource(), null);

		List<BindingSet> rows = new ArrayList<>();
		try (CloseableIteration<BindingSet> iteration = strategy.precompile(query)
				.evaluate(EmptyBindingSet.getInstance())) {
			while (iteration.hasNext()) {
				rows.add(iteration.next());
			}
		}

		assertEquals(1, rows.size(), "the zero-length path matches the left-bound endpoint itself");
		assertEquals(notInGraph, rows.get(0).getValue("r"));
	}

	/**
	 * The same mapping-parameterized contract for OPTIONAL right operands: an OPTIONAL containing a zero-or-one
	 * property path over a left-bound endpoint must extend the left solution with the zero-length match of that
	 * endpoint.
	 */
	@Test
	public void zeroLengthPathOptionalRightOperandStaysCorrelated() {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		IRI notInGraph = vf.createIRI("urn:not-in-graph");

		BindingSetAssignment values = new BindingSetAssignment();
		QueryBindingSet bs = new QueryBindingSet();
		bs.addBinding("x", notInGraph);
		values.setBindingSets(List.of(bs));

		QueryRoot query = new QueryRoot(new LeftJoin(values, new ZeroLengthPath(Var.of("x"), Var.of("r"))));

		StrictEvaluationStrategy strategy = new StrictEvaluationStrategy(new EmptyTripleSource(), null);

		List<BindingSet> rows = new ArrayList<>();
		try (CloseableIteration<BindingSet> iteration = strategy.precompile(query)
				.evaluate(EmptyBindingSet.getInstance())) {
			while (iteration.hasNext()) {
				rows.add(iteration.next());
			}
		}

		assertEquals(1, rows.size());
		assertEquals(notInGraph, rows.get(0).getValue("r"),
				"the OPTIONAL zero-length path extends the left solution with its own endpoint");
	}
}
